from gpio import *
from time import *
from ioeclient import *
from physical import *
import math
from environment import *

ENVIRONMENT_NAME = "Smoke"

state = 0
level = 0
ALARM_LEVEL = 40

def main():
    setup()
    while True:
		loop()

def setup():
    IoEClient.setup({
        "type": "Smoke Detector",
        "states": [{
            "name": "Alarm",
            "type": "bool",
            "controllable": False
        },
        {
            "name": "Level",
            "type": "number",
            "controllable": False
        }]
    })

    restoreProperty("Alarm Level", 40)
    IoEClient.onInputReceive(onInputReceiveDone)
    add_event_detect(0, detect)

    state = restoreProperty("state", 0)
    setState(state)

def onInputReceiveDone(data):
    processData(data, True)

def detect():
    processData(customRead(0), False)

def restoreProperty(propertyName, defaultValue):
    value = getDeviceProperty(getName(), propertyName)
    if  not (value is "" or value is None):
        if  type(defaultValue) is int :
            value = int(value)

        setDeviceProperty(getName(), propertyName, value)
        return value
    return defaultValue

def loop():
    global ENVIRONMENT_NAME
    value = Environment.get(ENVIRONMENT_NAME)
    if value >= 0:
        setLevel(Environment.get(ENVIRONMENT_NAME))
    #print(value)
    sleep(1)


def processData(data, bIsRemote):
    if len(data) <= 0 :
        return
    data = data.split(",")
    setState(int(data[0]))


def sendReport():
    global state
    global level
    report = str(state) + "," + str(level);   # comma seperated states
    IoEClient.reportStates(report)
    setDeviceProperty(getName(), "state", state)
    setDeviceProperty(getName(), "level", level)


def setState(newState):
    global state
    state = newState

    if newState is 0:
        digitalWrite(1, LOW)
    else:
        digitalWrite(1, HIGH)

    sendReport()


def setLevel(newLevel):
    global level
    if level == newLevel:
        return

    level = newLevel
    if level > ALARM_LEVEL:
        setState(1)
    else:
        setState(0)

    sendReport()

if __name__ == "__main__":
    main()

var ENVIRONMENT_NAME = "Smoke";

var state = 0;
var level = 0;
var ALARM_LEVEL = 40;

function setup() {

	IoEClient.setup({
		type: "Smoke Detector",
		states: [{
			name: "Alarm",
			type: "bool",
			controllable: false
		},
		{
			name: "Level",
			type: "number",
			controllable: false
		}]
	});

	IoEClient.onInputReceive = function(input) {
		processData(input, true);
	};

	attachInterrupt(0, function() {
		processData(customRead(0), false);
	});

	state = restoreProperty("state", 0);
	restoreProperty("Alarm Level", 40);

	setState(state);


}

function restoreProperty(propertyName, defaultValue)
{
	var value = getDeviceProperty(getName(), propertyName);
	if ( !(value === "" || value == "undefined") ){
		if ( typeof(defaultValue) == "number" )
			value = Number(value);

		setDeviceProperty(getName(), propertyName, value);
		return value;
	}

	return defaultValue;
}

function loop() {
	var value = Environment.get(ENVIRONMENT_NAME);
	//Serial.println(value);
	if (value >= 0)
		setLevel(Environment.get(ENVIRONMENT_NAME));

	delay(1000);
}

function processData(data, bIsRemote) {
	if (data.length <= 0 )
		return;
	data = data.split(",");
	setState(parseInt(data[0]));
}

function sendReport()
{
	var report = state + "," + level;	// comma seperated states
	IoEClient.reportStates(report);
	setDeviceProperty(getName(), "state", state);
	setDeviceProperty(getName(), "level", level);
}

function setState(newState) {
	state = newState;

	if (newState === 0)
		digitalWrite(1, LOW);
	else
		digitalWrite(1, HIGH);

	sendReport();
}

function setLevel(newLevel) {
	if (level == newLevel)
		return;

	level = newLevel;
	if (level > ALARM_LEVEL)
		setState(1);
	else
		setState(0);

	sendReport();
}

